{
  "name": "LinkSense AI - Universal Summarizer",
  "description": "Transform any URL into concise, actionable insights using Gemini Pro, Google Search, and Veo. Features multi-link analysis, voice interaction, and video teaser generation.",
  "requestFramePermissions": [
    "microphone"
  ]
