export enum SummaryType {
  SHORT = 'Short',
  DETAILED = 'Detailed',
  BULLETS = 'Bullet Points',
  TAKEAWAYS = 'Key Takeaways'
}

export interface SummaryResult {
  url: string;
  title: string;
  paragraph: string;
  bullets: string[];
  insights: string[];
  readingTimeOriginal: number;
  readingTimeSummary: number;
  language: string;
  sources?: Array<{ web: { uri: string; title: string } }>;
}

export interface AppState {
  urls: string[];
  summaries: SummaryResult[];
  isLoading: boolean;
  selectedSummaryType: SummaryType;
  selectedLanguage: string;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { SummaryType, SummaryResult } from "../types";

const API_KEY = process.env.API_KEY || "";

export const summarizeUrl = async (
  url: string, 
  type: SummaryType, 
  language: string
): Promise<SummaryResult> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const prompt = `
    You are an intelligent web content summarizer.
    Task: Extract and summarize the content of this URL: ${url}

    Target Language: ${language}
    Summary Style: ${type}

    Instructions:
    1. Extract main readable content.
    2. Understand the topic accurately.
    3. Calculate reading time (original vs summary).
    4. Provide the result in the following JSON format exactly:
    {
      "title": "Page Title",
      "paragraph": "Summary text based on style",
      "bullets": ["point 1", "point 2", ...],
      "insights": ["fact 1", "fact 2", ...],
      "readingTimeOriginal": number (minutes),
      "readingTimeSummary": number (minutes),
      "language": "specified language"
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          paragraph: { type: Type.STRING },
          bullets: { type: Type.ARRAY, items: { type: Type.STRING } },
          insights: { type: Type.ARRAY, items: { type: Type.STRING } },
          readingTimeOriginal: { type: Type.NUMBER },
          readingTimeSummary: { type: Type.NUMBER },
          language: { type: Type.STRING }
        },
        required: ["title", "paragraph", "bullets", "insights", "readingTimeOriginal", "readingTimeSummary", "language"]
      }
    },
  });

  const data = JSON.parse(response.text || "{}");
  return {
    ...data,
    url,
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => chunk)
  };
};

export const generateVideoTeaser = async (summary: string): Promise<string> => {
  // Check for Veo API key selection
  const hasKey = await (window as any).aistudio?.hasSelectedApiKey();
  if (!hasKey) {
    await (window as any).aistudio?.openSelectKey();
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const videoPrompt = `A high quality cinematic video representing the following topic: ${summary.substring(0, 200)}`;

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: videoPrompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const res = await fetch(`${downloadLink}&key=${API_KEY}`);
  const blob = await res.blob();
  return URL.createObjectURL(blob);
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';

interface VoiceAssistantProps {
  context: string;
}

const VoiceAssistant: React.FC<VoiceAssistantProps> = ({ context }) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const decodeAudioData = async (
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
  ): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const createBlob = (data: Float32Array) => {
    const int16 = new Int16Array(data.length);
    for (let i = 0; i < data.length; i++) {
      int16[i] = data[i] * 32768;
    }
    let binary = '';
    const bytes = new Uint8Array(int16.buffer);
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return {
      data: btoa(binary),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startSession = async () => {
    setIsConnecting(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-09-2025',
      callbacks: {
        onopen: () => {
          setIsConnecting(false);
          setIsActive(true);
          const source = audioContextRef.current!.createMediaStreamSource(stream);
          const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
          scriptProcessor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const pcmBlob = createBlob(inputData);
            sessionPromise.then((session) => {
              session.sendRealtimeInput({ media: pcmBlob });
            });
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(audioContextRef.current!.destination);
        },
        onmessage: async (message: LiveServerMessage) => {
          const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (base64Audio && outputAudioContextRef.current) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContextRef.current.currentTime);
            const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContextRef.current, 24000, 1);
            const source = outputAudioContextRef.current.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(outputAudioContextRef.current.destination);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += audioBuffer.duration;
            sourcesRef.current.add(source);
            source.onended = () => sourcesRef.current.delete(source);
          }
          if (message.serverContent?.interrupted) {
            sourcesRef.current.forEach(s => s.stop());
            sourcesRef.current.clear();
            nextStartTimeRef.current = 0;
          }
        },
        onerror: (e) => console.error('Live Error', e),
        onclose: () => {
          setIsActive(false);
          setIsConnecting(false);
        },
      },
      config: {
        responseModalities: [Modality.AUDIO],
        systemInstruction: `You are a helpful assistant discussing the following summarized content: ${context}. Help the user understand it better.`,
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } }
      }
    });

    sessionRef.current = await sessionPromise;
  };

  const stopSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    setIsActive(false);
  };

  return (
    <div className="flex flex-col items-center p-4 bg-indigo-50 rounded-xl border border-indigo-100 mt-6">
      <div className="flex items-center gap-4 mb-4">
        <div className={`w-3 h-3 rounded-full ${isActive ? 'bg-green-500 animate-pulse' : 'bg-gray-300'}`}></div>
        <h3 className="font-semibold text-indigo-900">Live Voice Deep-Dive</h3>
      </div>
      <p className="text-sm text-indigo-700 text-center mb-4 max-w-sm">
        Talk to Gemini about these summaries. Ask for clarifications, examples, or deeper insights.
      </p>
      {!isActive ? (
        <button
          onClick={startSession}
          disabled={isConnecting}
          className="bg-indigo-600 text-white px-6 py-2 rounded-full font-medium hover:bg-indigo-700 transition disabled:opacity-50"
        >
          {isConnecting ? 'Connecting...' : 'Start Voice Chat'}
        </button>
      ) : (
        <button
          onClick={stopSession}
          className="bg-red-500 text-white px-6 py-2 rounded-full font-medium hover:bg-red-600 transition"
        >
          End Session
        </button>
      )}
    </div>
  );
};

export default VoiceAssistant;

import React, { useState } from 'react';
import { SummaryResult } from '../types';
import { generateVideoTeaser } from '../services/geminiService';

interface SummaryCardProps {
  result: SummaryResult;
}

const SummaryCard: React.FC<SummaryCardProps> = ({ result }) => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [isGeneratingVideo, setIsGeneratingVideo] = useState(false);

  const handleExportText = () => {
    const text = `
Title: ${result.title}
URL: ${result.url}
Summary: ${result.paragraph}
Key Points:
${result.bullets.map(b => `- ${b}`).join('\n')}
Insights:
${result.insights.map(i => `- ${i}`).join('\n')}
Reading Time Saved: ${result.readingTimeOriginal - result.readingTimeSummary} minutes
    `;
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${result.title.replace(/\s+/g, '_')}_summary.txt`;
    a.click();
  };

  const handleGenerateVideo = async () => {
    setIsGeneratingVideo(true);
    try {
      const url = await generateVideoTeaser(result.paragraph);
      setVideoUrl(url);
    } catch (err) {
      console.error(err);
      alert("Failed to generate video. Ensure you have selected an API key from a paid project.");
    } finally {
      setIsGeneratingVideo(false);
    }
  };

  return (
    <div className="glass p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition-shadow">
      <div className="flex justify-between items-start mb-4">
        <h2 className="text-xl font-bold text-gray-800 leading-tight pr-4">{result.title}</h2>
        <div className="flex gap-2">
           <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-xs font-semibold whitespace-nowrap">
            Saved {result.readingTimeOriginal - result.readingTimeSummary} min
          </span>
        </div>
      </div>

      <div className="mb-6">
        <p className="text-gray-600 leading-relaxed italic mb-4">"{result.paragraph}"</p>

        <div className="grid md:grid-cols-2 gap-6">
          <div>
            <h4 className="font-semibold text-gray-700 mb-2 flex items-center gap-2">
              <svg className="w-4 h-4 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"></path></svg>
              Key Takeaways
            </h4>
            <ul className="space-y-1">
              {result.bullets.map((b, i) => (
                <li key={i} className="text-sm text-gray-600 flex items-start gap-2">
                  <span className="text-blue-400 mt-1">•</span> {b}
                </li>
              ))}
            </ul>
          </div>
          <div>
            <h4 className="font-semibold text-gray-700 mb-2 flex items-center gap-2">
              <svg className="w-4 h-4 text-purple-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
              Smart Insights
            </h4>
            <ul className="space-y-1">
              {result.insights.map((ins, i) => (
                <li key={i} className="text-sm text-gray-600 flex items-start gap-2">
                  <span className="text-purple-400 mt-1">•</span> {ins}
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>

      {result.sources && result.sources.length > 0 && (
        <div className="mb-4 pt-4 border-t border-gray-100">
          <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">Sources (Google Search Grounding)</p>
          <div className="flex flex-wrap gap-2">
            {result.sources.map((s: any, i) => (
              s.web && (
                <a 
                  key={i} 
                  href={s.web.uri} 
                  target="_blank" 
                  rel="noopener noreferrer" 
                  className="text-xs text-blue-600 bg-blue-50 px-2 py-1 rounded hover:bg-blue-100 truncate max-w-[200px]"
                >
                  {s.web.title || s.web.uri}
                </a>
              )
            ))}
          </div>
        </div>
      )}

      {videoUrl && (
        <div className="mt-4 rounded-xl overflow-hidden border border-gray-200">
          <video src={videoUrl} controls className="w-full" />
        </div>
      )}

      <div className="flex gap-3 mt-6">
        <button 
          onClick={handleExportText}
          className="flex-1 flex items-center justify-center gap-2 py-2 px-4 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition text-sm font-medium"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
          Export Text
        </button>
        <button 
          onClick={handleGenerateVideo}
          disabled={isGeneratingVideo}
          className="flex-1 flex items-center justify-center gap-2 py-2 px-4 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition text-sm font-medium disabled:opacity-50"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"></path></svg>
          {isGeneratingVideo ? 'Creating Teaser...' : 'Create Video Teaser'}
        </button>
      </div>
    </div>
  );
};

export default SummaryCard;

import React, { useState, useCallback } from 'react';
import { SummaryType, AppState, SummaryResult } from './types';
import { summarizeUrl } from './services/geminiService';
import SummaryCard from './components/SummaryCard';
import VoiceAssistant from './components/VoiceAssistant';

const LANGUAGES = ['English', 'Spanish', 'French', 'German', 'Chinese', 'Japanese', 'Hindi'];

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    urls: [''],
    summaries: [],
    isLoading: false,
    selectedSummaryType: SummaryType.SHORT,
    selectedLanguage: 'English'
  });

  const handleUrlChange = (index: number, value: string) => {
    const newUrls = [...state.urls];
    newUrls[index] = value;
    setState(prev => ({ ...prev, urls: newUrls }));
  };

  const addUrlField = () => {
    setState(prev => ({ ...prev, urls: [...prev.urls, ''] }));
  };

  const removeUrlField = (index: number) => {
    const newUrls = state.urls.filter((_, i) => i !== index);
    setState(prev => ({ ...prev, urls: newUrls.length ? newUrls : [''] }));
  };

  const processSummaries = async () => {
    const validUrls = state.urls.filter(u => u.trim() !== '');
    if (validUrls.length === 0) return;

    setState(prev => ({ ...prev, isLoading: true, summaries: [] }));

    try {
      const results: SummaryResult[] = [];
      for (const url of validUrls) {
        const result = await summarizeUrl(url, state.selectedSummaryType, state.selectedLanguage);
        results.push(result);
      }
      setState(prev => ({ ...prev, summaries: results, isLoading: false }));
    } catch (err) {
      console.error(err);
      alert("Something went wrong while summarizing. Please check your URLs.");
      setState(prev => ({ ...prev, isLoading: false }));
    }
  };

  const totalTimeSaved = state.summaries.reduce(
    (acc, curr) => acc + (curr.readingTimeOriginal - curr.readingTimeSummary), 
    0
  );

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="sticky top-0 z-50 glass border-b border-gray-200">
        <div className="max-w-5xl mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg">L</div>
            <h1 className="text-2xl font-black tracking-tight text-gray-900">LinkSense <span className="text-indigo-600">AI</span></h1>
          </div>
          <div className="hidden md:flex items-center gap-6">
            <div className="text-right">
              <p className="text-xs text-gray-500 font-bold uppercase tracking-widest">Total Time Saved</p>
              <p className="text-lg font-bold text-indigo-600 leading-none">{totalTimeSaved} Minutes</p>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 mt-12">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-extrabold text-gray-900 mb-4 tracking-tight">Turn long links into <span className="text-indigo-600">instant wisdom.</span></h2>
          <p className="text-lg text-gray-600 max-w-2xl mx-auto">Paste any URL below. We use Gemini Pro with Search Grounding to extract key facts and insights across any language.</p>
        </div>

        {/* URL Inputs Area */}
        <section className="bg-white rounded-3xl p-8 shadow-xl shadow-indigo-100/50 border border-indigo-50 mb-12">
          <div className="space-y-4 mb-8">
            {state.urls.map((url, index) => (
              <div key={index} className="flex gap-2">
                <div className="relative flex-1">
                  <input
                    type="text"
                    placeholder="https://example.com/article"
                    value={url}
                    onChange={(e) => handleUrlChange(index, e.target.value)}
                    className="w-full px-5 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition"
                  />
                  {state.urls.length > 1 && (
                    <button 
                      onClick={() => removeUrlField(index)}
                      className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-red-500 p-1"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                    </button>
                  )}
                </div>
              </div>
            ))}
            <button 
              onClick={addUrlField}
              className="text-indigo-600 font-semibold text-sm flex items-center gap-1 hover:text-indigo-700 transition pl-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg>
              Add another URL
            </button>
          </div>

          <div className="grid md:grid-cols-2 gap-6 mb-8">
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 ml-1">Summary Style</label>
              <select 
                value={state.selectedSummaryType}
                onChange={(e) => setState(prev => ({ ...prev, selectedSummaryType: e.target.value as SummaryType }))}
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                {Object.values(SummaryType).map(type => (
                  <option key={type} value={type}>{type}</option>
                ))}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 ml-1">Language</label>
              <select 
                value={state.selectedLanguage}
                onChange={(e) => setState(prev => ({ ...prev, selectedLanguage: e.target.value }))}
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                {LANGUAGES.map(lang => (
                  <option key={lang} value={lang}>{lang}</option>
                ))}
              </select>
            </div>
          </div>

          <button
            onClick={processSummaries}
            disabled={state.isLoading || state.urls.every(u => !u.trim())}
            className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold text-lg hover:bg-indigo-700 transition transform active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-indigo-200"
          >
            {state.isLoading ? (
              <span className="flex items-center justify-center gap-3">
                <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                Analyzing Webpages...
              </span>
            ) : "Generate Smart Summaries"}
          </button>
        </section>

        {/* Results Section */}
        {state.summaries.length > 0 && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {state.summaries.map((res, i) => (
              <SummaryCard key={i} result={res} />
            ))}

            <VoiceAssistant context={JSON.stringify(state.summaries)} />
          </div>
        )}

        {/* Empty State */}
        {!state.isLoading && state.summaries.length === 0 && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-16 opacity-60">
             <div className="p-6 bg-white rounded-2xl border border-gray-100 text-center">
               <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4 font-bold text-xl">1</div>
               <h3 className="font-bold mb-2">Multi-Link Support</h3>
               <p className="text-sm text-gray-500">Paste one or many URLs to summarize everything at once.</p>
             </div>
             <div className="p-6 bg-white rounded-2xl border border-gray-100 text-center">
               <div className="w-12 h-12 bg-purple-50 text-purple-600 rounded-full flex items-center justify-center mx-auto mb-4 font-bold text-xl">2</div>
               <h3 className="font-bold mb-2">Video Teasers</h3>
               <p className="text-sm text-gray-500">Generate cinematic video summaries for your social media.</p>
             </div>
